  var rows = tbl.querySelectorAll('tbody tr');
  var tableHtml = '<table><thead><tr>' +
    '<th>Produit</th><th>March├®</th><th>Rot./mois</th><th>Besoin '+moisCible+'m</th><th>Stock</th><th>Qt├® ├á cder</th><th>Colis.</th><th>TVA%</th><th>Rem%</th><th>UG</th><th>Qt├® totale</th><th>PA cat HT</th><th>PA net HT</th><th>PV TTC</th><th>CA cde</th><th>MB%</th>' +
    '</tr></thead><tbody>';
  rows.forEach(function(row) {
    tableHtml += '<tr>';
    row.querySelectorAll('td').forEach(function(td) {
      tableHtml += '<td>' + td.innerHTML + '</td>';
    });
    tableHtml += '</tr>';
  });
