function decCarteEcheance45fdm(d) {
  // ├ëch├®ance ┬½ 45 jours fin de mois ┬╗ : date du jour + 45 j, ramen├®e ├á la fin de ce mois-l├á
  d = d || new Date();
  var e = new Date(d.getTime() + 45 * 86400000);
  var fin = new Date(e.getFullYear(), e.getMonth() + 1, 0);
  var jours = Math.round((fin - d) / 86400000);
  return { date: fin, jours: jours };
}
function decCarteNorm(s) {
  return (s || '').toUpperCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^A-Z0-9]+/g, ' ').trim();
}
function decCarteMatchTous(offre, prods) {
  // Deux passes : 1) EAN exact pour TOUTES les lignes, 2) repli nom sur le reste
  // (├®vite qu'une ligne similaire ┬½ vole ┬╗ par nom un produit destin├® ├á une ligne EAN ult├®rieure)
  var used = {}, result = {};
  offre.forEach(function(o, idx) {
    for (var i = 0; i < prods.length; i++) {
      if (used[i]) continue;
      var e = (prods[i].ean || '');
      if (e && e.slice(-13) === o[0]) { used[i] = true; result[idx] = prods[i]; return; }
    }
  });
  offre.forEach(function(o, idx) {
    if (result[idx]) return;
    var toks = decCarteNorm(o[1]).split(' ').filter(function(t){ return t.length >= 2; });
    var best = -1, bestScore = 0;
    for (var j = 0; j < prods.length; j++) {
      if (used[j]) continue;
      var L = decCarteNorm(prods[j].lib);
      var hit = 0;
      toks.forEach(function(t){ if (L.indexOf(t) >= 0) hit++; });
      var score = toks.length > 0 ? hit / toks.length : 0;
      if (score > bestScore) { bestScore = score; best = j; }
    }
    if (best >= 0 && bestScore >= 0.7) { used[best] = true; result[idx] = prods[best]; }
  });
  return result;
}
// ===== IMPORT G├ëN├ëRIQUE D'UN BON DE COMMANDE SDAV (PDF) =====
function decEan13Valide(ean) {
  if (!/^\d{13}$/.test(ean)) return false;
  var s = 0;
  for (var i = 0; i < 12; i++) s += parseInt(ean[i], 10) * (i % 2 === 0 ? 1 : 3);
  return (10 - (s % 10)) % 10 === parseInt(ean[12], 10);
}
function decCarteParseBonSDAV(text) {
  var num = function(s){ return parseFloat(s.replace(',', '.')); };
  // Format A (Marque Verte) : EAN Libell├® Multiple Brut FDL Net (3 prix)
  var reA = /(\d{13})\s+(.{3,140}?)\s+(\d{1,3})\s+(\d+,\d{2})\s*Ôé¼\s+(\d+,\d{2})\s*Ôé¼\s+(\d+,\d{2})\s*Ôé¼/g;
  // Format B (Th├®a) : EAN Libell├® Multiple PrixCat PrixRemis├® (2 prix, pas de fil de l'eau)
  var reB = /(\d{13})\s+(.{3,140}?)\s+(\d{1,3})\s+(\d+,\d{2})\s*Ôé¼\s+(\d+,\d{2})\s*Ôé¼/g;
  var out = [], vus = {}, m;
  while ((m = reA.exec(text)) !== null) {
    var ean = m[1];
    if (vus[ean]) continue;
    vus[ean] = true;
    out.push([ean, m[2].replace(/\s+/g, ' ').trim(), parseInt(m[3], 10) || 1, num(m[4]), num(m[5]), num(m[6])]);
  }
  if (out.length === 0) {
    while ((m = reB.exec(text)) !== null) {
      var ean2 = m[1];
      if (vus[ean2]) continue;
      vus[ean2] = true;
      var brut = num(m[4]), net = num(m[5]);
      if (net > brut + 0.005) continue; // garde-fou : remis├® doit ├¬tre Ôëñ catalogue
      // Pas de prix ┬½ fil de l'eau ┬╗ distinct pour Th├®a : FDL = brut (gain = remise SDAV pure)
      out.push([ean2, m[2].replace(/\s+/g, ' ').trim(), parseInt(m[3], 10) || 1, brut, brut, net]);
    }
  }
  var fr = text.match(/Franco de port\s*:\s*(\d+)/i);
  // Comptage crois├® : tous les EAN-13 valides pr├®sents dans le texte (candidats produits)
  var cands = {}, cm, reAll = /\b(\d{13})\b/g;
  while ((cm = reAll.exec(text)) !== null) { if (decEan13Valide(cm[1])) cands[cm[1]] = true; }
  return { lignes: out, franco: fr ? parseInt(fr[1], 10) : null, candidatsList: Object.keys(cands) };
}
var _pdfjsReady = false;
function decCartePdfEnsure(cb) {
  if (_pdfjsReady && window.pdfjsLib) { cb(); return; }
  var s = document.createElement('script');
  s.src = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js';
  s.onload = function() {
    window.pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
    _pdfjsReady = true;
    cb();
  };
  s.onerror = function() { alert('Impossible de charger le lecteur PDF ÔÇö v├®rifie ta connexion.'); };
  document.head.appendChild(s);
}
function decCarteImportBonSDAV(input) {
  var file = input.files[0];
  if (!file) return;
  var res = document.getElementById('dec-carte-res');
  if (res) res.innerHTML = '<span style="font-size:11px;color:var(--text-ter)">ÔÅ│ Lecture du bon de commande...</span>';
  decCartePdfEnsure(function() {
    var reader = new FileReader();
    reader.onload = function(e) {
      window.pdfjsLib.getDocument({ data: new Uint8Array(e.target.result) }).promise.then(function(pdf) {
        var pages = [];
        var chain = Promise.resolve();
        for (var i = 1; i <= pdf.numPages; i++) {
          (function(n) {
            chain = chain.then(function() {
              return pdf.getPage(n).then(function(page) {
                return page.getTextContent().then(function(tc) {
                  pages.push(tc.items.map(function(it){ return it.str; }).join(' '));
                });
              });
            });
          })(i);
        }
        chain.then(function() {
          var parsed = decCarteParseBonSDAV(pages.join(' '));
          if (parsed.lignes.length === 0) {
            if (res) res.innerHTML = '<span style="font-size:11px;color:var(--danger)">Aucune ligne produit reconnue dans ce PDF ÔÇö est-ce bien un bon de commande SDAV (colonnes EAN / multiple / prix brut / FDL / net) ?</span>';
            return;
          }
          decCarteOffreImp = parsed.lignes;
          decCarteOffreTitre = '­ƒôÑ ' + (file.name || 'Bon SDAV').replace(/\.pdf$/i, '') + ' (' + parsed.lignes.length + ' r├®f.)';
          if (parsed.franco !== null) { var fEl = document.getElementById('dec-carte-franco'); if (fEl) fEl.value = parsed.franco; }
          decCarteValidationImport(parsed);
        });
      }).catch(function(err) {
        if (res) res.innerHTML = '<span style="font-size:11px;color:var(--danger)">Erreur de lecture du PDF : ' + err.message + '</span>';
      });
    };
    reader.readAsArrayBuffer(file);
  });
}

function decCarteOffreGB() { decCarteOffreRender(OFFRE_SDAV_MV_GB, 'Offre SDAV gamme blanche'); }
var decCarteOffreImp = null;
var decCarteOffreTitre = '';
function decCarteCatalogueEanMap() {
  // Croisement avec le catalogue du labo (condLabos) : ean -> prix tarif
  var map = {};
  try {
    var cible = (decCarteLabo || '').toUpperCase();
    Object.keys(condLabos).forEach(function(k) {
      var nom = ((condLabos[k] || {}).nom || '').toUpperCase();
      if (!nom) return;
      if (cible.indexOf(nom) >= 0 || nom.indexOf(cible) >= 0 || nom.split(' ').some(function(w){ return w.length > 4 && cible.indexOf(w) >= 0; })) {
        (condLabos[k].produits || []).forEach(function(p) { if (p.ean) map[String(p.ean)] = p.pu_catalogue; });
      }
    });
  } catch(e) {}
  return map;
}
function decCarteValidationImport(parsed) {
  var res = document.getElementById('dec-carte-res');
  if (!res) return;
  var tarifs = decCarteCatalogueEanMap();
  var nbAnomalies = 0, lignes = '';
  parsed.lignes.forEach(function(o, i) {
    var pbs = [];
    if (!decEan13Valide(o[0])) pbs.push('cl├® EAN invalide');
    if (!(o[5] <= o[4] + 0.005 && o[4] <= o[3] + 0.005)) pbs.push('prix incoh├®rents (net Ôëñ FDL Ôëñ brut attendu)');
    var remI = o[3] > 0 ? 1 - o[5] / o[3] : 0;
    if (remI < -0.005 || remI > 0.9) pbs.push('remise implicite ' + Math.round(remI * 100) + '% suspecte');
    var tCat = tarifs[o[0]];
    var catCell = 'ÔÇö';
    if (tCat !== undefined) {
      if (Math.abs(tCat - o[3]) <= Math.max(0.01, tCat * 0.01)) catCell = '<span style="color:var(--accent-text)">Ô£ô ' + tCat.toFixed(2).replace('.', ',') + '</span>';
      else { catCell = '<span style="color:var(--danger)">ÔÜá tarif ' + tCat.toFixed(2).replace('.', ',') + ' Ôé¼</span>'; pbs.push('brut Ôëá tarif catalogue'); }
    }
    if (pbs.length > 0) nbAnomalies++;
    lignes += '<tr style="' + (pbs.length > 0 ? 'background:#fdecec' : '') + '">'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);font-family:monospace;font-size:10px">' + o[0] + (decEan13Valide(o[0]) ? ' <span style="color:var(--accent-text)">Ô£ô</span>' : ' <span style="color:var(--danger)">Ô£ù</span>') + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border)">' + o[1] + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right">├ù' + o[2] + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right">' + o[3].toFixed(2).replace('.', ',') + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right">' + o[4].toFixed(2).replace('.', ',') + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right;font-weight:600">' + o[5].toFixed(2).replace('.', ',') + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right">' + Math.round(remI * 100) + '%</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right">' + catCell + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);font-size:10px;color:var(--danger)">' + pbs.join(' ┬À ') + '</td>'
      + '</tr>';
  });
  var eansExtraits = {};
  parsed.lignes.forEach(function(o){ eansExtraits[o[0]] = true; });
  var manquants = (parsed.candidatsList || []).filter(function(e){ return !eansExtraits[e]; }).length;
  var html = '<div style="font-size:12px;font-weight:700;margin-top:6px">­ƒöÄ Contr├┤le de l\u2019import ÔÇö ' + parsed.lignes.length + ' lignes extraites'
    + (parsed.franco !== null ? ' ┬À franco d├®tect├® ' + parsed.franco + ' Ôé¼' : '') + '</div>';
  if (manquants > 0) html += '<div style="margin-top:4px;padding:8px 10px;background:#fdecec;border-radius:var(--radius-sm);font-size:12px;color:var(--danger);font-weight:600">ÔÜá´©Å ' + manquants + ' code(s) EAN pr├®sent(s) dans le PDF n\u2019ont PAS ├®t├® extraits en ligne produit ÔÇö compare avec le bon avant de valider.</div>';
  if (nbAnomalies > 0) html += '<div style="margin-top:4px;padding:8px 10px;background:#fdecec;border-radius:var(--radius-sm);font-size:12px;color:var(--danger);font-weight:600">ÔÜá´©Å ' + nbAnomalies + ' ligne(s) en anomalie (surlign├®es en rouge) ÔÇö v├®rifie-les sur le PDF.</div>';
  if (manquants === 0 && nbAnomalies === 0) html += '<div style="margin-top:4px;padding:8px 10px;background:var(--accent-bg);border-radius:var(--radius-sm);font-size:12px;color:var(--accent-text);font-weight:600">Ô£ô Tous les contr├┤les passent : cl├®s EAN valides, prix coh├®rents' + (Object.keys(tarifs).length > 0 ? ', tarifs conformes au catalogue' : '') + ', aucun EAN du PDF laiss├® de c├┤t├®.</div>';
  html += '<table style="width:auto;border-collapse:collapse;font-size:11px;table-layout:auto;margin-top:6px">'
    + '<tr style="color:var(--text-ter)"><td style="padding:3px 10px">EAN (cl├®)</td><td style="padding:3px 10px">Libell├®</td><td style="padding:3px 10px;text-align:right">Mult.</td><td style="padding:3px 10px;text-align:right">Brut</td><td style="padding:3px 10px;text-align:right">FDL</td><td style="padding:3px 10px;text-align:right">Net</td><td style="padding:3px 10px;text-align:right">Remise</td><td style="padding:3px 10px;text-align:right">Tarif catalogue</td><td style="padding:3px 10px">Anomalies</td></tr>'
    + lignes + '</table></div>'
    + '<div style="margin-top:8px"><button type="button" onclick="decCarteValiderImport()" style="font-size:12px;padding:8px 16px;background:' + (nbAnomalies > 0 || manquants > 0 ? 'var(--warn)' : 'var(--accent)') + ';color:#fff;border:none;border-radius:var(--radius-sm);cursor:pointer;font-weight:700">'
    + (nbAnomalies > 0 || manquants > 0 ? 'ÔÜá´©Å Valider malgr├® les alertes et calculer' : 'Ô£ô Valider et calculer les quantit├®s') + '</button></div>';
  res.innerHTML = html;
}
function decCarteValiderImport() {
  if (!decCarteOffreImp) return;
  decCarteOffreRender(decCarteOffreImp, decCarteOffreTitre);
}
function decCarteOffreRender(OFFRE, TITRE) {
  var res = document.getElementById('dec-carte-res');
  if (!res || !decCarteLabo || !decOspharmProds[decCarteLabo]) return;
  var payJ = parseFloat(document.getElementById('dec-carte-pay').value) || 75;
  var franco = parseFloat(document.getElementById('dec-carte-franco').value) || 100;
  var f = decGetPeriode() === 'encours' ? 12 / Math.max(decMoisEchus(), 1) : 1;
  var hz = payJ / 360;
  var prods = decOspharmProds[decCarteLabo];
  var matches = decCarteMatchTous(OFFRE, prods);
  var aFdlDistinct = OFFRE.some(function(o){ return Math.abs(o[3] - o[4]) > 0.005; });
  var gainLabel = aFdlDistinct ? 'Gain vs fil de l\u2019eau' : 'Remise (\u20ac)';
  var totBrut = 0, totFdl = 0, totNet = 0, caHz = 0, nbMatch = 0, sansVente = 0, multTropGrand = 0, lignes = '';
  OFFRE.forEach(function(o, oIdx) {
    var ean = o[0], lib = o[1], mult = o[2], brut = o[3], fdl = o[4], net = o[5];
    var p = matches[oIdx] || null;
    var qteAn = p ? p.qte * f : 0;
    var q75 = qteAn * hz;
    // Arrondi au multiple INF├ëRIEUR : tout doit ├¬tre vendu avant l'├®ch├®ance
    var qteCmd = Math.floor(q75 / mult) * mult;
    if (qteCmd === 0) { if (q75 > 0) multTropGrand++; else sansVente++; return; }
    nbMatch++;
    var mNet = qteCmd * net, mFdl = qteCmd * fdl, mBrut = qteCmd * brut;
    totNet += mNet; totFdl += mFdl; totBrut += mBrut;
    if (p) caHz += (p.caht * f) * hz;
    var remLigne = brut > 0 ? (1 - net / brut) * 100 : 0;
    lignes += '<tr>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border)">' + lib + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right">' + Math.round(qteAn) + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right">' + q75.toFixed(1) + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right;color:var(--text-ter)">├ù' + mult + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right;font-weight:700">' + qteCmd + '</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right;color:var(--text-ter)">' + Math.round(qteCmd / Math.max(qteAn / 360, 0.001)) + ' j</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right">' + net.toFixed(2).replace('.', ',') + ' Ôé¼</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right">' + mNet.toFixed(2).replace('.', ',') + ' Ôé¼</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right">' + Math.round(remLigne) + '%</td>'
      + '<td style="padding:3px 10px;border-top:1px solid var(--border);text-align:right;color:var(--accent-text);font-weight:600">+' + (mFdl - mNet).toFixed(2).replace('.', ',') + ' Ôé¼</td>'
      + '</tr>';
  });
  if (nbMatch === 0) { res.innerHTML = '<span style="font-size:11px;color:var(--danger)">Aucune ligne de l\u2019offre ne correspond ├á des ventes dans ton import. Si ton export Ospharm a une colonne EAN/CIP, r├®importe le fichier (le rapprochement sera exact).</span>'; return; }
  var remTot = totBrut > 0 ? (1 - totNet / totBrut) * 100 : 0;
  var gainFdl = totFdl - totNet;
  var dateEch = new Date(Date.now() + payJ * 86400000);
  var html = '<div style="font-size:12px;font-weight:700;margin-top:6px">­ƒôï ' + TITRE + ' ÔÇö commande aujourd\u2019hui, <span style="color:var(--accent-text)">facture payable vers le ' + dateEch.toLocaleDateString('fr-FR') + '</span> (' + Math.round(payJ) + ' j)</div>'
    + '<div style="font-size:10px;color:var(--text-ter)">' + nbMatch + ' lignes avec ventes ┬À ' + sansVente + ' r├®f. sans rotation ignor├®es' + (multTropGrand > 0 ? ' ┬À ' + multTropGrand + ' r├®f. vendues mais multiple trop grand pour tout ├®couler avant l\u2019├®ch├®ance (laisse-les au fil de l\u2019eau)' : '') + '</div>'
    + '<table style="width:auto;border-collapse:collapse;font-size:11px;table-layout:auto;margin-top:4px">'
    + '<tr style="color:var(--text-ter)"><td style="padding:3px 10px">Produit (offre UPP)</td><td style="padding:3px 10px;text-align:right">Qt├®/an</td><td style="padding:3px 10px;text-align:right">Sorties ' + Math.round(payJ) + ' j</td><td style="padding:3px 10px;text-align:right">Mult.</td><td style="padding:3px 10px;text-align:right">Qt├® ├á commander</td><td style="padding:3px 10px;text-align:right">├ëcoul├® en</td><td style="padding:3px 10px;text-align:right">Prix net</td><td style="padding:3px 10px;text-align:right">Montant net</td><td style="padding:3px 10px;text-align:right">Remise vs brut</td><td style="padding:3px 10px;text-align:right">' + gainLabel + '</td></tr>'
    + lignes
    + '<tr><td style="padding:5px 10px;border-top:2px solid var(--border);font-weight:700">TOTAL</td><td></td><td></td><td></td><td></td><td></td><td></td>'
    + '<td style="padding:5px 10px;border-top:2px solid var(--border);text-align:right;font-weight:700">' + totNet.toFixed(2).replace('.', ',') + ' Ôé¼</td>'
    + '<td style="padding:5px 10px;border-top:2px solid var(--border);text-align:right;font-weight:700">' + Math.round(remTot) + '%</td>'
    + '<td style="padding:5px 10px;border-top:2px solid var(--border);text-align:right;font-weight:700;color:var(--accent-text)">+' + gainFdl.toFixed(2).replace('.', ',') + ' Ôé¼</td></tr>'
    + '</table></div>';
  html += totNet >= franco
    ? '<div style="margin-top:6px;font-size:12px;color:var(--accent-text);font-weight:600">Ô£ô Franco ' + Math.round(franco) + ' Ôé¼ atteint (' + Math.round(totNet) + ' Ôé¼) ÔÇö pas de frais de port.</div>'
    : '<div style="margin-top:6px;font-size:12px;color:var(--warn);font-weight:600">ÔÜá´©Å Franco ' + Math.round(franco) + ' Ôé¼ non atteint (' + Math.round(totNet) + ' Ôé¼) : allonge l\u2019horizon ou compl├¿te, sinon r├®assort fil de l\u2019eau.</div>';
  var coussin = caHz - totNet;
  html += '<div style="margin-top:6px;padding:10px 12px;background:' + (coussin >= 0 ? 'var(--accent-bg)' : '#fdecec') + ';border-radius:var(--radius-sm);font-size:12px">'
    + (coussin >= 0
      ? '<strong>Ô£à Tu ne sors pas de cash ÔÇö et tout est vendu avant l\u2019├®ch├®ance</strong> (quantit├®s arrondies au multiple inf├®rieur, colonne ┬½ ├®coul├® en ┬╗ Ôëñ ' + Math.round(payJ) + ' j) : ces produits auront r├®-encaiss├® Ôëê ' + Math.round(caHz).toLocaleString('fr') + ' Ôé¼ avant que tu ne paies ' + Math.round(totNet).toLocaleString('fr') + ' Ôé¼ ÔÇö coussin de <strong>' + Math.round(coussin).toLocaleString('fr') + ' Ôé¼</strong>.' + (aFdlDistinct ? 'Cash gagn├® vs fil de l\u2019eau : <strong>+' + Math.round(gainFdl).toLocaleString('fr') + ' Ôé¼</strong> , ' : 'Remise totale obtenue : <strong>' + Math.round(gainFdl).toLocaleString('fr') + ' Ôé¼</strong>, soit ') + 'remise r├®elle ' + Math.round(remTot) + '% vs tarif brut.'
      : '<strong>ÔÜá´©Å Les arrondis aux multiples gonflent la commande au-del├á de tes encaissements de l\u2019horizon</strong> (' + Math.round(caHz).toLocaleString('fr') + ' Ôé¼ encaiss├®s pour ' + Math.round(totNet).toLocaleString('fr') + ' Ôé¼ ├á payer). Retire les lignes ├á faible rotation dont le multiple impose trop de stock.')
    + '</div>'
    + '<div style="font-size:10px;color:var(--text-ter);margin-top:4px">Rapprochement offreÔåöventes par EAN quand ton export en a une colonne, sinon par nom (score ÔëÑ 70%). Qt├®s arrondies au multiple de commande sup├®rieur. ┬½ Gain vs fil de l\u2019eau ┬╗ = (prix FDL ÔêÆ prix net SDAV) ├ù qt├®.</div>';
  res.innerHTML = html;
}

var decFiltreCatalogue = true; // par defaut, n'affiche que les produits presents dans le catalogue du labo (Calculateur)

function decToggleFiltreCatalogue(checked) {
  decFiltreCatalogue = !!checked;
  if (decCurrentStats && decCurrentStats.labo) decAfficherResume(decCurrentStats.labo);
}

function decAfficherResume(labo) {
  var el = document.getElementById('dec-resume');
  if (!el || !decOspharmProds || !decOspharmProds[labo]) return;
  var selP = document.getElementById('dec-periode');
  if (selP) selP.value = decGetPeriode();
  var prodsBruts = decOspharmProds[labo];
  // Filtre "catalogue" : ne garder que les produits Ospharm dont l'EAN existe dans le catalogue du
  // labo correspondant dans le Calculateur (condLabos[x].produits) ÔÇö evite d'afficher des refs
  // remontees par Ospharm sous le meme nom de labo mais jamais importees/suivies ici (ex: gammes
  // non distribuees par la pharmacie, doublons de nom de laboratoire chez Ospharm, etc.).
  var laboObj = decTrouverLaboObj(labo);
  var catalogueEans = null;
  if (laboObj && laboObj.produits && laboObj.produits.length > 0) {
    catalogueEans = {};
    laboObj.produits.forEach(function(p){ if (p.ean) catalogueEans[String(p.ean).replace(/\D/g,'')] = true; });
  }
  var filtreActif = decFiltreCatalogue && catalogueEans;
  var prods = filtreActif ? prodsBruts.filter(function(p){ return p.ean && catalogueEans[String(p.ean).replace(/\D/g,'')]; }) : prodsBruts;
  var nbExclus = prodsBruts.length - prods.length;
  var sorted = prods.slice().sort(function(a,b){ return b.caht - a.caht; });
  var totCaht = 0, totMarge = 0, totStock = 0, totQte = 0;
  for (var i = 0; i < prods.length; i++) {
    totCaht    += prods[i].caht;
    totMarge   += prods[i].marge;
    totStock   += prods[i].stock;
    totQte     += prods[i].qte;
  }
  var tauxMarge = totCaht > 0 ? (totMarge / totCaht) * 100 : 0;
  var nbRefs = prods.filter(function(p){ return p.caht > 0; }).length;
  var periode = decGetPeriode();
  var mois = periode === 'encours' ? decMoisEchus() : 12;
  var caAnnu = mois > 0 ? totCaht * 12 / mois : totCaht;
  var margeAnnu = mois > 0 ? totMarge * 12 / mois : totMarge;
  var html = '<strong style="font-size:13px">' + labo + '</strong>';
  html += '<span style="font-size:10px;color:var(--text-ter);margin-left:8px">' + (periode === 'encours' ? 'ann\u00e9e en cours \u00b7 ' + mois + ' mois \u00e9chus' : 'ann\u00e9e liss\u00e9e \u00b7 12 mois') + '</span>';
  if (catalogueEans) {
    html += '<label style="display:inline-flex;align-items:center;gap:5px;margin-left:14px;font-size:11px;color:var(--text-sec);cursor:pointer">' +
      '<input type="checkbox" ' + (decFiltreCatalogue ? 'checked' : '') + ' onchange="decToggleFiltreCatalogue(this.checked)"> ' +
      'Catalogue uniquement' + (nbExclus > 0 ? ' <span style="color:var(--text-ter)">(' + nbExclus + ' ref. Ospharm hors catalogue masqu\u00e9' + (nbExclus>1?'es':'e') + ')</span>' : '') +
      '</label>';
  }
  html += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:8px;margin:8px 0 12px">';
  html += '<div><span style="font-size:10px;color:var(--text-ter)">CA p\u00e9riode HT</span><br><strong>' + Math.round(totCaht).toLocaleString('fr') + ' \u20ac</strong></div>';
  if (periode === 'encours') html += '<div><span style="font-size:10px;color:var(--text-ter)">CA annualis\u00e9</span><br><strong>' + Math.round(caAnnu).toLocaleString('fr') + ' \u20ac</strong></div>';
  html += '<div><span style="font-size:10px;color:var(--text-ter)">Marge totale</span><br><strong>' + Math.round(totMarge).toLocaleString('fr') + ' \u20ac</strong></div>';
  html += '<div><span style="font-size:10px;color:var(--text-ter)">Taux de marge</span><br><strong>' + tauxMarge.toFixed(1) + '%</strong></div>';
  html += '<div><span style="font-size:10px;color:var(--text-ter)">R├®f├®rences</span><br><strong>' + nbRefs + '</strong></div>';
  html += '<div><span style="font-size:10px;color:var(--text-ter)">Stock (unit├®s)</span><br><strong>' + Math.round(totStock).toLocaleString('fr') + '</strong></div>';
  html += '</div>';
  var th = 'padding:6px 8px;font-size:10px;font-weight:600;text-transform:uppercase;background:#e8f5f0;text-align:right;border-bottom:1px solid var(--border)';
  var prodsN1 = (decOspharmProdsN1 && decOspharmProdsN1[labo]) ? decOspharmProdsN1[labo] : null;
  var hasN1 = !!prodsN1;
  html += '<div style="overflow-x:auto"><table style="width:auto;border-collapse:collapse;font-size:11px;table-layout:auto">';
  html += '<thead><tr>';
  html += '<th style="' + th + ';text-align:left">EAN</th>';
  html += '<th style="' + th + ';text-align:left">Produit</th>';
  if (!hasN1) html += '<th style="' + th + '">Qt├®</th>';
  if (hasN1) {
    html += '<th style="' + th + '">Qt├® N-1</th>';
    html += '<th style="' + th + '">Qt├® N</th>';
    html += '<th style="' + th + '">├ëvol %</th>';
  }
  html += '<th style="' + th + '">CA HT</th>';
  html += '<th style="' + th + '">Marge</th>';
  html += '<th style="' + th + '">Taux</th>';
  html += '<th style="' + th + '">Stock</th>';
  html += '</tr></thead><tbody>';
  var totQteN1 = 0, totQteN1Found = false;
  for (var i = 0; i < sorted.length; i++) {
    var p = sorted[i];
    var tm = p.caht > 0 ? (p.marge / p.caht * 100) : 0;
    var bg = i % 2 === 0 ? '#fff' : 'var(--surface2)';
    var td = 'padding:5px 8px;border-bottom:0.5px solid var(--border);text-align:right;background:' + bg;
    html += '<tr>';
    html += '<td style="' + td + ';text-align:left;white-space:nowrap;font-family:monospace;font-size:10px;color:var(--text-ter)">' + (p.ean || '') + '</td>';
    html += '<td style="' + td + ';text-align:left;white-space:nowrap">' + p.lib + '</td>';
    if (!hasN1) html += '<td style="' + td + '">' + Math.round(p.qte).toLocaleString('fr') + '</td>';
    if (hasN1) {
      var qN1 = decTrouverQteN1(p, prodsN1);
      if (qN1 !== null) { totQteN1 += qN1; totQteN1Found = true; }
      var evol = (qN1 !== null && qN1 > 0) ? ((p.qte - qN1) / qN1 * 100) : null;
      html += '<td style="' + td + (qN1 === null ? ';color:var(--text-ter)' : '') + '">' + (qN1 === null ? 'ÔÇö' : Math.round(qN1).toLocaleString('fr')) + '</td>';
      html += '<td style="' + td + '">' + Math.round(p.qte).toLocaleString('fr') + '</td>';
      if (evol === null) {
        html += '<td style="' + td + ';color:var(--text-ter)">ÔÇö</td>';
      } else {
        var evolColor = evol >= 0 ? 'var(--accent-text)' : '#c01c28';
        html += '<td style="' + td + ';color:' + evolColor + ';font-weight:600">' + (evol >= 0 ? '+' : '') + evol.toFixed(1) + '%</td>';
      }
    }
    html += '<td style="' + td + '">' + Math.round(p.caht).toLocaleString('fr') + ' Ôé¼</td>';
    html += '<td style="' + td + '">' + Math.round(p.marge).toLocaleString('fr') + ' Ôé¼</td>';
    html += '<td style="' + td + ';color:' + (tm >= 28 ? 'var(--accent-text)' : '#c01c28') + ';font-weight:600">' + tm.toFixed(1) + '%</td>';
    html += '<td style="' + td + '">' + Math.round(p.stock).toLocaleString('fr') + '</td>';
    html += '</tr>';
  }
  var tdT = 'padding:6px 8px;text-align:right;font-weight:700;border-top:2px solid var(--border);background:var(--surface2)';
  html += '<tr>';
  html += '<td style="' + tdT + '"></td>';
  html += '<td style="' + tdT + ';text-align:left">TOTAL (' + nbRefs + ' r├®f.)</td>';
  if (!hasN1) html += '<td style="' + tdT + '">' + Math.round(totQte).toLocaleString('fr') + '</td>';
  if (hasN1) {
    var evolTot = (totQteN1Found && totQteN1 > 0) ? ((totQte - totQteN1) / totQteN1 * 100) : null;
    html += '<td style="' + tdT + '">' + (totQteN1Found ? Math.round(totQteN1).toLocaleString('fr') : 'ÔÇö') + '</td>';
    html += '<td style="' + tdT + '">' + Math.round(totQte).toLocaleString('fr') + '</td>';
    html += '<td style="' + tdT + (evolTot === null ? '' : (';color:' + (evolTot >= 0 ? 'var(--accent-text)' : '#c01c28'))) + '">' + (evolTot === null ? 'ÔÇö' : (evolTot >= 0 ? '+' : '') + evolTot.toFixed(1) + '%') + '</td>';
  }
  html += '<td style="' + tdT + '">' + Math.round(totCaht).toLocaleString('fr') + ' Ôé¼</td>';
  html += '<td style="' + tdT + '">' + Math.round(totMarge).toLocaleString('fr') + ' Ôé¼</td>';
  html += '<td style="' + tdT + ';color:' + (tauxMarge >= 28 ? 'var(--accent-text)' : '#c01c28') + '">' + tauxMarge.toFixed(1) + '%</td>';
  html += '<td style="' + tdT + '">' + Math.round(totStock).toLocaleString('fr') + '</td>';
  html += '</tr></tbody></table></div>';
  el.innerHTML = html;
  el.style.display = 'block';
  decCurrentStats = { labo: labo, caht: caAnnu, caPeriode: totCaht, margeEur: margeAnnu, taux: tauxMarge, mois: mois, periode: periode, nbRefs: nbRefs };
  decAfficherConditions(labo);
  decAfficherCarte(labo);
  decAfficherOffresSpec(labo);
  decAfficherTheaAnalyse(labo);
  decRenderStockTarget();
}

// Repere visuel + garde-fou : montre clairement a quel labo le prochain import "Stock reel LGPI"
// va s'appliquer (celui actuellement affiche), et desactive le champ tant qu'aucun labo n'est affiche
// pour eviter d'appliquer un stock au mauvais labo sans s'en rendre compte.
function decRenderStockTarget() {
  var el = document.getElementById('dec-stock-target');
  var fileInput = document.getElementById('dec-file-stock');
  var labo = decCurrentStats ? decCurrentStats.labo : null;
  var pret = labo && decOspharmProds && decOspharmProds[labo];
  if (el) {
    el.innerHTML = pret
      ? 'Stock LGPI pour : <strong style="color:var(--accent-text)">' + labo + '</strong>'
      : '<span style="color:var(--warn)">ÔÜá Affiche d\'abord un labo (recherche ci-dessus ou Vue COALIA) avant d\'importer le stock.</span>';
  }
  if (fileInput) fileInput.disabled = !pret;
}


// ===== DECISION RDV : CONDITIONS LABO + VERDICT =====
var decCurrentStats = null;
var decCondCurrent = null;

function decGetPeriode() {
  try { var p = localStorage.getItem('decPeriode'); return p === 'encours' ? 'encours' : 'lissee'; } catch(e) { return 'lissee'; }
}
function decMoisEchus(d) {
  // Mois ├®chus depuis le 1er janvier (en juin -> 5 : janv a mai). En janvier, repli sur 12.
  d = d || new Date();
  var m = d.getMonth();
  return m === 0 ? 12 : m;
}
function decChangerPeriode() {
  var sel = document.getElementById('dec-periode');
  if (sel) { try { localStorage.setItem('decPeriode', sel.value); } catch(e) {} }
  if (decCurrentStats) decAfficherResume(decCurrentStats.labo);
}

function decGetCondData() {
  try { return JSON.parse(localStorage.getItem('decCondLabos') || '{}'); } catch(e) { return {}; }
}
function decSaveCondData(d) {
  try { localStorage.setItem('decCondLabos', JSON.stringify(d)); } catch(e) {}
}
function decGetSeuils() {
  var s = { caOui: 5000, remOui: 35 };
  try {
    var saved = JSON.parse(localStorage.getItem('decSeuils') || '{}');
    if (saved.caOui > 0) s.caOui = saved.caOui;
    if (saved.remOui > 0) s.remOui = saved.remOui;
  } catch(e) {}
  return s;
}
function decParseUG(str) {
  // "12+2" -> 2/(12+2) = 14.3% ; "10" -> 10%
  if (!str) return 0;
  str = String(str).trim();
  var m = str.match(/^(\d+)\s*\+\s*(\d+)$/);
  if (m) {
    var a = parseFloat(m[1]), o = parseFloat(m[2]);
    return (a + o) > 0 ? (o / (a + o)) * 100 : 0;
  }
  var n = parseFloat(str.replace(',', '.'));
  return isNaN(n) ? 0 : n;
}
function decNormaliserCond(c) {
  // Migration ancien format { remise:'30' } -> marches[]
  c = c || {};
  if (!c.marches || !c.marches.length) {
    var rem = parseFloat(c.remise);
    c.marches = [{ nom: 'G\u00e9n\u00e9ral', mots: '', remise: isNaN(rem) ? '' : rem }];
  }
  if (c.ug === undefined) c.ug = '';
  if (c.rfa === undefined) c.rfa = '';
  if (c.franco === undefined) c.franco = '';
  if (c.seuilCA === undefined || c.seuilRem === undefined) {
    var defS = decGetSeuils();
    if (c.seuilCA === undefined) c.seuilCA = defS.caOui;
    if (c.seuilRem === undefined) c.seuilRem = defS.remOui;
  }
  if (!c.marchesRetenus) c.marchesRetenus = [];
  if (c.dateDebutEngagement === undefined) c.dateDebutEngagement = '';
  if (c.dateFinEngagement === undefined) c.dateFinEngagement = '';
  if (!c.offresSpec) c.offresSpec = [];
  c.offresSpec.forEach(function(o) {
    if ((o.seuils === undefined || o.remises === undefined) && o.paliers) {
      var p = decParsePaliers(o.paliers);
      o.seuils = p.map(function(x){ return x.seuil; }).join(', ');
      o.remises = p.map(function(x){ return x.remise; }).join(', ');
    }
    if (o.seuils === undefined) o.seuils = '';
    if (o.remises === undefined) o.remises = '';
    delete o.paliers;
  });
  delete c.remise;
  return c;
}
// Match un mot-cle en tant que MOT ENTIER (limite de mot), pas une simple sous-chaine -
// sinon le mot-cle "BIAFINE" matche aussi "CICABIAFINE" (sous-chaine presente), ce qui est faux.
function motCleMatch(lib, motCle) {
  if (!motCle) return false;
  var echappe = motCle.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  try { return new RegExp('\\b' + echappe + '\\b').test(lib); } catch(e) { return lib.indexOf(motCle) !== -1; }
}
function decAffecterMarches(labo, marches, prodsOverride, eanToMarche) {
  // Affecte chaque produit Ospharm a son marche :
  // 1) PRIORITE : marche officiel saisi dans le Catalogue (eanToMarche, par EAN), si le produit y est connu.
  //    - marche renseigne et correspondant a un marche negocie -> ce marche
  //    - marche vide ou "Non classe" (declasse volontairement) -> HORS MARCHE (exclu des stats, pas de fallback mots-cles)
  // 2) Produit absent du catalogue (EAN inconnu) -> 1er marche dont un mot-cle matche le libelle,
  //    sinon 1er marche sans mots-cles (fourre-tout).
  var prods = prodsOverride || ((typeof decOspharmProds !== 'undefined' && decOspharmProds && decOspharmProds[labo]) ? decOspharmProds[labo] : []);
  var stats = [], motsM = [];
  var idxDef = -1; // -1 = aucun marche "fourre-tout" designe (mots-cles vides sur aucun marche) -> hors marche par defaut
  var labelToIdx = {};
  for (var j = 0; j < marches.length; j++) {
    stats.push({ ca: 0, nb: 0 });
    motsM.push(String(marches[j].mots || '').split(',').map(function(m){ return m.trim().toUpperCase(); }).filter(function(m){ return m.length > 0; }));
    labelToIdx[String(marches[j].nom || '').toUpperCase()] = j;
  }
  for (var j = 0; j < marches.length; j++) { if (motsM[j].length === 0) { idxDef = j; break; } }
  var caTot = 0, caPond = 0;
  for (var i = 0; i < prods.length; i++) {
    var lib = String(prods[i].lib || '').toUpperCase();
    var idx = -1; // -1 = pas encore tranche (EAN inconnu du catalogue) ; -2 = hors marche explicite (catalogue)
    var cleanEan = prods[i].ean ? String(prods[i].ean).replace(/\D/g, '') : '';
    if (eanToMarche && cleanEan && eanToMarche.hasOwnProperty(cleanEan)) {
      var mCat = String(eanToMarche[cleanEan] || '').toUpperCase();
      idx = labelToIdx.hasOwnProperty(mCat) ? labelToIdx[mCat] : -2;
    }
    if (idx === -1) {
      for (var j = 0; j < marches.length; j++) {
        var hit = false;
        for (var k = 0; k < motsM[j].length; k++) { if (motCleMatch(lib, motsM[j][k])) { hit = true; break; } }
        if (hit) { idx = j; break; }
      }
    }
    if (idx < 0) continue; // -1 = EAN inconnu sans mot-cle correspondant -> hors marche ; -2 = declasse au catalogue
    stats[idx].ca += prods[i].caht;
    stats[idx].nb++;
    caTot += prods[i].caht;
    caPond += prods[i].caht * (parseFloat(marches[idx].remise) || 0);
  }
  return { stats: stats, caTot: caTot, remisePonderee: caTot > 0 ? caPond / caTot : (idxDef >= 0 ? (parseFloat(marches[idxDef].remise) || 0) : 0) };
}
