// Extrait les dates du nom de fichier : "Toutes_les_ventes_YYYY-MM-DD_YYYY-MM-DD.xlsx"
// Retourne { debut, fin, nb_jours, coeff } ou null
function meqDetecterPeriode(filename) {
  var m = filename.match(/(\d{4}-\d{2}-\d{2})_(\d{4}-\d{2}-\d{2})/);
  if (!m) return null;
  var d1 = new Date(m[1]);
  var d2 = new Date(m[2]);
  if (isNaN(d1) || isNaN(d2) || d2 <= d1) return null;
  var nb_jours = Math.round((d2 - d1) / 86400000) + 1;
  var coeff = Math.round((365 / nb_jours) * 100) / 100;
  return { debut: m[1], fin: m[2], nb_jours: nb_jours, coeff: coeff };
}

