function cipmapLigne(row, i) {
  return '<tr style="border-bottom:1px solid var(--border)" data-search="' + (row.old+' '+row.new+' '+row.lib+' '+row.labo).toLowerCase() + '">'
    + '<td style="padding:9px 12px;font-family:monospace;font-size:12px;color:var(--text-sec)">' + row.old + '</td>'
    + '<td style="padding:9px 12px;font-family:monospace;font-size:12px;font-weight:600">' + row.new + '</td>'
    + '<td style="padding:9px 12px;font-size:13px">' + (row.lib || 'ÔÇö') + '</td>'
    + '<td style="padding:9px 12px;font-size:12px;color:var(--text-sec)">' + (row.labo || 'ÔÇö') + '</td>'
    + '<td style="padding:9px 12px;font-size:11px;color:var(--text-ter)">' + (row.date || '') + '</td>'
    + '<td style="padding:9px 12px;text-align:right"><button onclick="cipmapSupprimer(' + i + ')" style="padding:3px 8px;font-size:11px;border:1px solid var(--border);border-radius:var(--radius-sm);background:transparent;color:var(--danger);cursor:pointer">Ô£ò</button></td>'
    + '</tr>';
}

function cipmapAjouter() {
  document.getElementById('cipmap-form').style.display = 'flex';
  document.getElementById('cipmap-old').focus();
}

function cipmapConfirmer() {
  var oldEan = (document.getElementById('cipmap-old').value || '').trim();
  var newEan = (document.getElementById('cipmap-new').value || '').trim();
  var lib    = (document.getElementById('cipmap-lib').value || '').trim();
  var labo   = (document.getElementById('cipmap-labo').value || '').trim();
  if (!oldEan || !newEan) { alert('EAN ancien et EAN nouveau obligatoires.'); return; }
  var today = new Date().toISOString().slice(0,10);
  cipMapData.unshift({ old: oldEan, new: newEan, lib: lib, labo: labo, date: today });
  cipmapSave();
  cipmapRender();
}

function cipmapSupprimer(i) {
  if (!confirm('Supprimer cette correspondance ?')) return;
  cipMapData.splice(i, 1);
  cipmapSave();
  cipmapRender();
}

function cipmapFiltrer() {
  var q = (document.getElementById('cipmap-search').value || '').toLowerCase();
  var rows = document.querySelectorAll('#cipmap-tbody tr');
  rows.forEach(function(r) {
    r.style.display = (!q || r.dataset.search.indexOf(q) >= 0) ? '' : 'none';
  });
}

function cipmapExporter() {
  if (!cipMapData.length) { alert('Aucune donn├®e ├á exporter.'); return; }
  var csv = 'EAN ancien,EAN nouveau,Libell├®,Labo,Date\n';
  cipMapData.forEach(function(r) {
    csv += [r.old, r.new, '"'+(r.lib||'').replace(/"/g,'""')+'"', r.labo||'', r.date||''].join(',') + '\n';
  });
  var a = document.createElement('a');
  a.href = 'data:text/csv;charset=utf-8,' + encodeURIComponent(csv);
  a.download = 'cip_map_' + new Date().toISOString().slice(0,10) + '.csv';
  a.click();
}
function cipmapFermerForm() { var f = document.getElementById('cipmap-form'); if(f) f.style.display='none'; }

// ============================================================
// SUIVI SELL-IN ÔÇö Achats cumul├®s depuis d├®but p├®riode
// ============================================================
var sellInData = {}; // { laboId: { ean: { qte, total_ht, cmds } } }
var sellInManuel = {}; // { laboId: { marcheId: { qte, debut, fin } } } ÔÇö saisie manuelle par march├®

function sellInGetLaboId(fournisseur) {
  var fu = fournisseur.toUpperCase();
  var firstWord = fu.split(/\s+/)[0] || '';
  return Object.keys(condLabos).find(function(k) {
    var nom = (condLabos[k].nom || '').toUpperCase();
    if (fu.indexOf('PERRIGO') >= 0 && nom.indexOf('PERRIGO') >= 0) return true;
    if (fu.indexOf('AVENE') >= 0 && nom.indexOf('AVENE') >= 0) return true;
    if (fu.indexOf('ARKOPHARMA') >= 0 && nom.indexOf('ARKOPHARMA') >= 0) return true;
    if (fu.indexOf('KENVUE') >= 0 && nom.indexOf('KENVUE') >= 0) return true;
    if (fu.indexOf('URGO') >= 0 && nom.indexOf('URGO') >= 0) return true;
    if (fu.indexOf('BOIRON') >= 0 && nom.indexOf('BOIRON') >= 0) return true;
    if (fu.indexOf('COOPER') >= 0 && nom.indexOf('COOPER') >= 0) return true;
    if (firstWord.length >= 4 && nom.indexOf(firstWord) >= 0) return true;
    return false;
  }) || null;
}

function sellInParserPDF(arrayBuffer) {
  // Utiliser PDF.js (d├®j├á charg├® via cdnjs si disponible) ou fallback text
  // On utilise une approche fetch + FileReader c├┤t├® navigateur
  return new Promise(function(resolve) {
    // Extraire le texte via FileReader en mode binaire puis regex
    var bytes = new Uint8Array(arrayBuffer);
    var str = '';
    for (var i = 0; i < bytes.length; i++) str += String.fromCharCode(bytes[i]);
    
    // Extraire le texte du PDF via regex sur les streams PDF
    var textContent = '';
    var tdMatches = str.match(/\(([^)]{2,80})\)\s*Tj/g) || [];
    tdMatches.forEach(function(m) {
      var inner = m.replace(/^\(/, '').replace(/\)\s*Tj$/, '');
      textContent += inner + '\n';
    });
    
    resolve(textContent);
  });
}

async function sellInExtrairePDFTexte(file) {
  // Extraire le texte via PDF.js
  var ab = await file.arrayBuffer();
  var pdf = await pdfjsLib.getDocument({ data: ab }).promise;
  var fullText = '';
  for (var p = 1; p <= pdf.numPages; p++) {
    var page = await pdf.getPage(p);
    var tc   = await page.getTextContent();
    var items = tc.items.map(function(i) { return i.str; });
    fullText += items.join(' ') + '\n';
  }

  // Parser le texte : PDF.js produit des tokens s├®par├®s par espaces
  // On cherche les EANs (10-13 chiffres) puis on lit les tokens suivants
  var fournisseurM = fullText.match(/Fournisseur\s*:\s*(.+?)(?:T├®l├®phone|Page)/);
  var fournisseur  = fournisseurM ? fournisseurM[1].replace(/\s+/g,' ').trim() : '';
  // Garder seulement jusqu'├á la fin du nom labo (avant pr├®nom d├®l├®gu├®)
  // Pattern : couper avant "PRENOM NOM" (maj+min maj+min)
  fournisseur = fournisseur.replace(/\s+[A-Z][a-z├®├¿├á├╣]+\s+[A-Z][a-z├®├¿├á├╣]+.*$/, '').trim();
  fournisseur = fournisseur.replace(/\s*Page\s*\d.*$/, '').trim();

  var cmdM   = fullText.match(/Commande no:\s*(\d+)\s+du:\s*([\d\/]+)/);
  var numCmd  = cmdM ? cmdM[1] : '?';
  var dateCmd = cmdM ? cmdM[2] : '?';

  // Parser token par token
  var tokens = fullText.split(/\s+/);
  var lignes = [];
  var i = 0;
  while (i < tokens.length) {
    var tok = tokens[i];
    // EAN : 10-13 chiffres
    if (/^\d{10,13}$/.test(tok)) {
      var ean = tok;
      i++;
      // Sauter les tokens de d├®signation jusqu'├á trouver qt├® (entier court)
      var desig = [];
      while (i < tokens.length && !/^\d{1,4}$/.test(tokens[i])) {
        desig.push(tokens[i]);
        i++;
        if (desig.length > 15) break;
      }
      var qte = i < tokens.length ? parseInt(tokens[i]) : 0;
      i++;
      // UG
      if (i < tokens.length && /^\d{1,3}$/.test(tokens[i])) i++;
      // Collecter les nombres d├®cimaux suivants (PA Cat, Rem1, Rem2, PA net, Total)
      var nums = [];
      while (i < tokens.length && /^[\d]+[,\.][\d]+$/.test(tokens[i])) {
        nums.push(parseFloat(tokens[i].replace(',','.')));
        i++;
      }
      if (qte > 0 && qte < 5000 && nums.length >= 2) {
        lignes.push({
          ean: ean,
          qte: qte,
          pa_net:   nums[nums.length - 2],
          total_ht: nums[nums.length - 1]
        });
      }
    } else {
      i++;
    }
  }

  return { fournisseur: fournisseur, num_cmd: numCmd, date_cmd: dateCmd, lignes: lignes };
}

async function sellInImporterPDF(input) {
  var files = input.files;
  if (!files || !files.length) return;

  var totalImported = 0;
  var errors = [];

  for (var f = 0; f < files.length; f++) {
    var file = files[f];
    try {
      var parsed = await sellInExtrairePDFTexte(file);
      var fournisseur = parsed.fournisseur || '';
      var numCmd  = parsed.num_cmd  || '?';
      var dateCmd = parsed.date_cmd || '?';
      var laboId  = sellInGetLaboId(fournisseur);

      if (!laboId) {
        errors.push(file.name + ' : labo "' + fournisseur + '" non trouv├® dans condLabos');
        continue;
      }

      if (!sellInData[laboId]) sellInData[laboId] = {};
      var imported = 0;

      (parsed.lignes || []).forEach(function(l) {
        var ean = String(l.ean || '').trim();
        if (ean.length < 10) return;
        var qte     = parseInt(l.qte)    || 0;
        var paNet   = parseFloat(l.pa_net)   || 0;
        var totalHt = parseFloat(l.total_ht) || 0;
        if (qte <= 0) return;
        if (!sellInData[laboId][ean]) sellInData[laboId][ean] = { qte: 0, total_ht: 0, cmds: [] };
        sellInData[laboId][ean].qte      += qte;
        sellInData[laboId][ean].total_ht += totalHt;
        sellInData[laboId][ean].cmds.push({ num: numCmd, date: dateCmd, qte: qte, pa: paNet });
        imported++;
      });

      totalImported += imported;
    } catch(e) {
      errors.push(file.name + ' : erreur extraction (' + e.message + ')');
    }
  }

  if (errors.length) alert('ÔÜá´©Å ' + errors.join('\n'));
  alert('Ô£à ' + totalImported + ' lignes sell-in import├®es depuis ' + files.length + ' PDF(s).');
  precommandeRender();
}

function sellInGetMarche(laboId, marche) {
  var mid = marche.id || marche.label;
  // Saisie manuelle prioritaire si pr├®sente
  if (sellInManuel[laboId] && sellInManuel[laboId][mid] !== undefined) {
    return sellInManuel[laboId][mid].qte || 0;
  }
  // Sinon cumul PDF
  if (!sellInData[laboId]) return 0;
  var total = 0;
  (marche.eans || []).forEach(function(ean) {
    if (sellInData[laboId][ean]) total += sellInData[laboId][ean].qte;
  });
  return total;
}

function sellInSaisieManuelle(laboId, marcheId, label, mode) {
  mode = mode || 'global';
  var existing = (sellInManuel[laboId] || {})[marcheId] || {};
  var currentDebut = existing.debut || '';
  var currentFin   = existing.fin   || '';

  var mc = JSON.parse(localStorage.getItem('cond_marches_commerciaux') || '{}');
  var marche = (mc[laboId] || {})[marcheId] || {};
  var eans = marche.eans || [];
  var nomByEan = {};
  Object.values(condLabos).forEach(function(l) {
    (l.produits || []).forEach(function(p) { if (p.ean && p.nom) nomByEan[p.ean] = p.nom; });
  });

  var btnGlobal  = '<button onclick="sellInSaisieManuelle(\''+laboId+'\',\''+marcheId+'\',\''+label+'\',\'global\')" style="padding:5px 12px;font-size:12px;border-radius:var(--radius-sm);cursor:pointer;border:1px solid var(--border);background:'+(mode==='global'?'var(--text)':'transparent')+';color:'+(mode==='global'?'#fff':'var(--text-sec)')+'">Par march├®</button>';
  var btnProduit = '<button onclick="sellInSaisieManuelle(\''+laboId+'\',\''+marcheId+'\',\''+label+'\',\'produit\')" style="padding:5px 12px;font-size:12px;border-radius:var(--radius-sm);cursor:pointer;border:1px solid var(--border);background:'+(mode==='produit'?'var(--text)':'transparent')+';color:'+(mode==='produit'?'#fff':'var(--text-sec)')+'">Par produit</button>';

  var inputZone = '';
  if (mode === 'global') {
    var currentQte = existing.qte !== undefined ? existing.qte : '';
    inputZone = '<div><label style="font-size:11px;color:var(--text-ter);text-transform:uppercase;display:block;margin-bottom:4px">Quantit├®s achet├®es (total march├®)</label>'
      + '<input id="si-qte-global" type="number" value="' + currentQte + '" min="0" placeholder="ex: 45" style="width:100%;padding:7px 10px;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;box-sizing:border-box"></div>';
  } else {
    var rows = eans.map(function(ean) {
      var nom = (nomByEan[ean] || ean).substring(0, 45);
      var val = (existing.produits || {})[ean] || '';
      return '<tr><td style="padding:5px 6px;font-size:11px;color:var(--text-sec)">' + nom + '</td>'
        + '<td style="padding:5px 4px;width:70px"><input data-ean="'+ean+'" type="number" value="'+val+'" min="0" style="width:100%;padding:4px 6px;border:1px solid var(--border);border-radius:4px;font-size:12px;text-align:center"></td></tr>';
    }).join('');
    inputZone = '<div style="max-height:250px;overflow-y:auto;border:1px solid var(--border);border-radius:var(--radius-sm)">'
      + '<table style="width:100%;border-collapse:collapse"><thead><tr>'
      + '<th style="text-align:left;padding:5px 6px;font-size:10px;color:var(--text-ter);border-bottom:1px solid var(--border)">Produit</th>'
      + '<th style="padding:5px 4px;font-size:10px;color:var(--text-ter);border-bottom:1px solid var(--border);text-align:center">Qt├®</th>'
      + '</tr></thead><tbody>' + rows + '</tbody></table></div>';
  }

  var hasExisting = Object.keys(existing).length > 0;
  var effacerBtn = hasExisting ? '<button onclick="sellInEffacerManuel(\''+laboId+'\',\''+marcheId+'\')" style="padding:7px 14px;border:1px solid var(--danger);border-radius:var(--radius-sm);background:transparent;color:var(--danger);font-size:13px;cursor:pointer">Effacer</button>' : '';

  var html = '<div style="position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.4);z-index:9999;display:flex;align-items:center;justify-content:center">'
    + '<div style="background:var(--surface);border-radius:var(--radius);padding:24px;width:420px;max-height:90vh;overflow-y:auto;box-shadow:0 8px 32px rgba(0,0,0,0.2)">'
    + '<h3 style="margin:0 0 12px;font-size:14px;font-weight:600">' + label + ' ÔÇö Saisie sell-in</h3>'
    + '<div style="display:flex;gap:6px;margin-bottom:16px">' + btnGlobal + btnProduit + '</div>'
    + '<div style="display:flex;flex-direction:column;gap:12px">'
    + '<div style="display:flex;gap:10px">'
    + '<div style="flex:1"><label style="font-size:11px;color:var(--text-ter);text-transform:uppercase;display:block;margin-bottom:4px">D├®but</label><input id="si-debut" type="date" value="' + currentDebut + '" style="width:100%;padding:7px 8px;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;box-sizing:border-box"></div>'
    + '<div style="flex:1"><label style="font-size:11px;color:var(--text-ter);text-transform:uppercase;display:block;margin-bottom:4px">Fin</label><input id="si-fin" type="date" value="' + currentFin + '" style="width:100%;padding:7px 8px;border:1px solid var(--border);border-radius:var(--radius-sm);font-size:13px;box-sizing:border-box"></div>'
    + '</div>'
    + inputZone
    + '</div>'
    + '<div style="display:flex;gap:8px;margin-top:20px;justify-content:flex-end">'
    + '<button onclick="sellInFermerModal()" style="padding:7px 14px;border:1px solid var(--border);border-radius:var(--radius-sm);background:transparent;font-size:13px;cursor:pointer">Annuler</button>'
    + effacerBtn
    + '<button onclick="sellInValiderManuel(\''+laboId+'\',\''+marcheId+'\',\''+mode+'\')" style="padding:7px 14px;background:var(--text);color:#fff;border:none;border-radius:var(--radius-sm);font-size:13px;cursor:pointer;font-weight:500">Enregistrer</button>'
    + '</div></div></div>';

  var oldModal = document.getElementById('si-modal');
  if (oldModal) oldModal.remove();
  var modal = document.createElement('div');
  modal.id = 'si-modal';
  modal.innerHTML = html;
  document.body.appendChild(modal);
}

function sellInValiderManuel(laboId, marcheId, mode) {
  var debut = (document.getElementById('si-debut') || {}).value || '';
  var fin   = (document.getElementById('si-fin')   || {}).value || '';
  if (!sellInManuel[laboId]) sellInManuel[laboId] = {};

  if (mode === 'produit') {
    var produits = {};
    var total = 0;
    document.querySelectorAll('#si-modal input[data-ean]').forEach(function(inp) {
      var q = parseInt(inp.value) || 0;
      if (q > 0) { produits[inp.dataset.ean] = q; total += q; }
    });
    sellInManuel[laboId][marcheId] = { qte: total, produits: produits, debut: debut, fin: fin, mode: 'produit' };
  } else {
    var qte = parseInt((document.getElementById('si-qte-global') || {}).value) || 0;
    sellInManuel[laboId][marcheId] = { qte: qte, debut: debut, fin: fin, mode: 'global' };
  }

  sellInFermerModal();
  precommandeRender();
}

function sellInEffacerManuel(laboId, marcheId) {
  if (sellInManuel[laboId]) delete sellInManuel[laboId][marcheId];
  var modal = document.getElementById('si-modal');
  if (modal) modal.remove();
  precommandeRender();
}
function precommandeSaisieBtn(laboId, marcheId, label) {
  sellInSaisieManuelle(laboId, marcheId, label);
}
function sellInFermerModal() {
  var m = document.getElementById('si-modal');
  if (m) m.remove();
}
function precommandeEditSeuil(laboId, marcheId) {
  var mc = JSON.parse(localStorage.getItem('cond_marches_commerciaux') || '{}');
  var marche = (mc[laboId] || {})[marcheId];
  if (!marche) return;

  var newSeuil = prompt('Modifier le seuil pour "' + marche.label + '" (actuellement ' + marche.seuil_unite + ' u.) :', marche.seuil_unite);
  if (newSeuil === null) return;
  var val = parseInt(newSeuil);
  if (isNaN(val) || val <= 0) { alert('Valeur invalide.'); return; }

  mc[laboId][marcheId].seuil_unite = val;
  localStorage.setItem('cond_marches_commerciaux', JSON.stringify(mc));
  precommandeRender();
}

